  return new Promise((resolve, reject) => {
    axios
      .post(
        'https://api.shard-ai.xyz/v1/chat/completions/', // API Endpoint
        {
          model: 'gpt-4o',
          messages: [
            {
              role: 'user',
              content: userInput
            }
          ]
        },
        {
          headers: {
            'Authorization': 'Bearer shard-raOzdk7Bi5r6qkM1Wa1WHfrSy9IEbrZ8L',
            'Content-Type': 'application/json'
          }
        }
