  <div class="code-block-wrapper">
    <div class="code-header">
      <span class="code-lang">{{ lang }}</span>
      <button @click="copyCode" class="copy-button">{{ buttonText }}</button>
    </div>
    <pre class="hljs"><code v-html="highlightedCode"></code></pre>
  </div>
</template>

<script>
import hljs from "highlight.js";

export default {
  props: {
    code: { type: String, required: true },
    lang: { type: String, default: "text" },
  },
  data() {
    return {
      buttonText: "复制",
    };
  },
  computed: {
    highlightedCode() {
      return hljs.highlight(this.code, { language: this.lang }).value; // 语法高亮
    },
  },
  methods: {
    copyCode() {
      navigator.clipboard.writeText(this.code); // 复制内容到剪贴板
      this.buttonText = "已复制"; // 显示反馈
      setTimeout(() => (this.buttonText = "复制"), 2000); // 两秒后恢复原始文本
    },
  },
};
</script>

<style>
/* 样式与你全局的样式一致 */
</style>
```

