#### **绑定点击事件实现复制功能**

在 Vue 的 `mounted()` 中监听所有带有 `copy-button` 类的按钮，并为每个按钮绑定复制功能。同时，我们从 `data-code` 属性中安全提取代码内容：

```javascript
mounted() {
  this.$nextTick(() => {
    // 获取所有代码块的复制按钮
    const buttons = document.querySelectorAll(".copy-button");

    buttons.forEach((button) => {
      button.addEventListener("click", () => {
        // 从 data-code 中获取要复制的代码内容
        const codeToCopy = button.getAttribute("data-code");
        navigator.clipboard.writeText(codeToCopy) // 写入剪贴板
          .then(() => {
            // 成功后的提示
            button.innerText = "已复制";
            setTimeout(() => {
              button.innerText = "复制";
            }, 2000);
          })
          .catch(() => {
            // 错误处理
            button.innerText = "复制失败";
            setTimeout(() => {
              button.innerText = "复制";
            }, 2000);
          });
      });
    });
  });
}
```

